import{G as o}from"./chunks/shared-links.CZ5QUsOH.js";import{C as t,o as a,c as s,j as i,a as n,E as l,k as c,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p={dir:"rtl"},m=JSON.parse('{"title":"معرفی","description":"","frontmatter":{},"headers":[],"relativePath":"fa/introduction.md","filePath":"fa/introduction.md"}'),h={name:"fa/introduction.md"},f=Object.assign(h,{setup(P){return(g,e)=>{const r=t("YoutubePlayer");return a(),s("div",null,[i("div",p,[e[0]||(e[0]=i("h1",{id:"معرفی",tabindex:"-1"},[i("i",{class:"ph ph-hand-waving"}),n(" معرفی "),i("a",{class:"header-anchor",href:"#معرفی","aria-label":'Permalink to "<i class="ph ph-hand-waving"></i> معرفی"'},"​")],-1)),l(r,{src:c(o).youtubeVideo},null,8,["src"]),e[1]||(e[1]=d('<p><strong>Web Adaptive Performance (WebAP)</strong> ابزاری برای بهینه‌سازی پویای برنامه‌های Unity WebGL است.</p><p>این ابزار به یافتن تعادل بین کیفیت بصری و FPS پایدار در طیف وسیعی از دستگاه‌ها، از رایانه‌های شخصی قدرتمند تا گوشی‌های هوشمند ضعیف، کمک می‌کند. به‌جای تکیه بر محدودیت‌های سخت، این افزونه زمان‌بندی فریم‌ها را در لحظه تحلیل می‌کند. این افزونه علت اصلی افت عملکرد را تشخیص داده، بار را به‌آرامی تا رسیدن به پایداری کاهش می‌دهد و در صورت به‌دست آوردن حاشیه عملکرد (Performance Headroom)، کیفیت را بازیابی می‌کند.</p><div class="tip custom-block"><p class="custom-block-title">تطبیق با دستگاه</p><p>پروژه Unity خود را به‌طور پیش‌فرض برای تنظیمات حداکثر کیفیت پیکربندی کنید. اگر دستگاه فعلی نتواند آن بار را تحمل کند، افزونه به‌طور خودکار آن را در حین اجرا (Runtime) کاهش می‌دهد.</p></div><h2 id="چرا-webap-را-انتخاب-کنیم؟" tabindex="-1">چرا WebAP را انتخاب کنیم؟ <a class="header-anchor" href="#چرا-webap-را-انتخاب-کنیم؟" aria-label="Permalink to &quot;چرا WebAP را انتخاب کنیم؟&quot;">​</a></h2><p><strong><i class="ph-bold ph-x"></i> چرا از پکیج رسمی Adaptive Performance استفاده نکنیم؟</strong><br> پکیج رسمی Unity ابزاری قدرتمند است، اما با WebGL سازگاری اساسی ندارد. این پکیج بر دو نوع ارائه‌دهنده (Provider) تکیه دارد که هر دو با محدودیت‌های مرورگر متوقف می‌شوند:<br> ۱. <strong>ارائه‌دهندگان بومی (Native Providers) (Android):</strong> برای بازیابی داده‌های حرارتی و مدیریت فرکانس به APIهای سیستم وابسته هستند. سندباکس (Sandbox) مرورگر از هرگونه دسترسی به سخت‌افزار جلوگیری می‌کند و این رویکرد را غیرممکن می‌سازد. استانداردهای جدید وب (مانند <em>Compute Pressure API</em>) تنها CPU را مانیتور می‌کنند و داده‌های دقیقی برای گرافیک سه‌بعدی ارائه نمی‌دهند.<br> ۲. <strong>ارائه‌دهنده پایه (Basic Provider):</strong> ارائه‌دهنده ریاضی چندپلتفرمی Unity. این ارائه‌دهنده به <code>FrameTimingManager</code> متکی است. با این حال، برای عملکرد این انجین به تایمرهای GPU سخت‌افزاری با دقت بالا نیاز دارد که به دلایل امنیتی (برای جلوگیری از حملات <em>Spectre/Meltdown</em>) در مرورگر مسدود یا به‌شدت مبهم شده‌اند. در نتیجه، Basic Provider رسمی عملاً در WebGL مقداردهی اولیه نمی‌شود.</p><p><strong><i class="ph-bold ph-check"></i> راه‌حل WebAP:</strong> ما رویکردی متناسب با ویژگی‌های وب طراحی کرده‌ایم. WebAP نیز از <code>FrameTimingManager</code> بهره می‌برد، اما به‌جای تکیه صرف بر تایمرهای مسدود شده GPU، از تحلیل هیوریستیک (Heuristic) ایمن استفاده می‌کند. این افزونه ناهنجاری‌های مرورگر (مانند تحریف متریک‌ها ناشی از <code>setTimeout</code> در Emscripten) را دور زده و از ریاضیات محض برای محاسبه گلوگاه‌ها (CPU در برابر GPU) استفاده می‌کند. این امر یک سیستم بهینه‌سازی سطح AAA ارائه می‌دهد که در هر مرورگری به‌صورت قانونی و پایدار عمل می‌کند.</p><p><strong><i class="ph-bold ph-x"></i> چرا از اسکریپت‌های مقیاس‌بندی استاندارد استفاده نکنیم؟</strong><br> راه‌حل‌های کلاسیک به‌سادگی وضوح صفحه را در اولین نشانه تأخیر کاهش می‌دهند. اگر برنامه به دلیل محاسبات پردازنده (فیزیک، اسکریپت‌ها، منطق) به‌جای رندر شدن با مشکل مواجه شود، این کار بی‌فایده است.</p><p><strong><i class="ph-fill ph-check-fat"></i> WebAP چگونه کار می‌کند:</strong></p><ul><li><i class="ph-fill ph-brain"></i> <strong>تشخیص گلوگاه (Bottleneck Detection)</strong><br> افزونه به‌طور ریاضی تعیین می‌کند که چه چیزی فریم را محدود می‌کند: CPU یا GPU. اگر فیزیک با تأخیر مواجه شود، سیستم فیزیک را بدون کاهش وضوح صفحه ساده می‌کند. بیش از ۱۲ مقیاس‌کننده (Scaler) مستقل (سایه‌ها، LODها، Layer Culling و غیره) برای این منظور در نظر گرفته شده است.</li><li><i class="ph-fill ph-hand-palm"></i> <strong>سیستم جریمه ضد یویو (Anti Yo-Yo Penalty System)</strong><br> این سیستم، مشکل رایج وضوح پویا هنگام چشمک‌زدن کیفیت (Quality flickering) را حل می‌کند. اگر بهبود گرافیک باعث افت فوری FPS شود، سیستم یک جریمه موقت (Penalty Lockout) را برای جلوگیری از افزایش بیشتر اجرا می‌کند.</li><li><i class="ph-fill ph-layout"></i> <strong>حفظ وضوح UI</strong><br> اگر حالت مقیاس‌بندی از طریق <code>RenderTexture</code> را انتخاب کنید، وضوح دنیای سه‌بعدی کاهش می‌یابد، اما رابط کاربری در مقیاس اصلی مرورگر (Native Browser Scaling) باقی می‌ماند. کامپوننت سفارشی <code>WebScaledPhysicsRaycaster</code> مختصات Ray را به‌طور خودکار محاسبه می‌کند تا کلیک‌ها روی اشیاء سه‌بعدی بدون در نظر گرفتن فشرده‌سازی فریم، بی‌نقص عمل کنند.</li><li><i class="ph-fill ph-lightning"></i> <strong>معماری Zero-GC</strong><br> کل پروژه با در نظر گرفتن صرفه‌جویی شدید در حافظه طراحی شده است. هسته از بافرهای حلقوی O(1) استفاده می‌کند و هیچ‌گونه تخصیص حافظه‌ای (Allocation) در حلقه <code>Update</code> انجام نمی‌دهد. در نتیجه، افزونه Garbage Collector (GC) را فعال نمی‌کند.</li><li><i class="ph-fill ph-broom"></i> <strong>پاکسازی سخت‌گیرانه نسخه نهایی (Build)</strong><br> بسیاری از Assetها با قرار دادن Prefabها و تکسچرهای خود در پوشه <code>Resources</code> (مجبور کردن انجین برای شامل کردن آن‌ها در Build) حجم نسخه نهایی را افزایش می‌دهند. معماری WebAP از این خطا جلوگیری می‌کند. مگر اینکه صریحاً به صحنه اضافه شوند، تمام ابزارها و رابط کاربری داشبورد به‌طور خودکار در طول کامپایل حذف می‌شوند. تنها هسته سبک‌وزن به پروژه نهایی می‌رسد.</li><li><i class="ph-fill ph-gear"></i> <strong>ادغام Plug-and-Play</strong><br> تنظیمات در یک رابط کاربری یکپارچه در بخش <em>Project Settings</em> متمرکز شده‌اند. افزونه به‌طور خودکار خود را به نسخه نهایی تزریق می‌کند — نیازی به قرار دادن دستی Prefabهای مدیریتی در صحنه‌های خود ندارید.</li></ul><h2 id="سازگاری" tabindex="-1">سازگاری <a class="header-anchor" href="#سازگاری" aria-label="Permalink to &quot;سازگاری&quot;">​</a></h2><ul><li><strong>نسخه Unity:</strong> نسخه <code>2020.3 LTS</code> و جدیدتر. این افزونه از APIهای مدرن استفاده می‌کند و ویژگی‌های جدید انجین (مانند پشتیبانی از <code>Mesh LOD Threshold</code> از نسخه Unity 6000.2+) را به‌طور خودکار اتخاذ می‌کند.</li><li><strong>پایپ‌لاین رندر (Render Pipeline):</strong> پشتیبانی کامل هم از Built-in Render Pipeline (BiRP) و هم از Universal Render Pipeline (URP).</li></ul>',11))])])}}});export{m as __pageData,f as default};
